		{"Absolute, home", page.KindHome, nil, []string{"/", ""}, "home page"},
		{"Absolute, page", page.KindPage, nil, []string{"/about.md", "/about"}, "about page"},
		{"Absolute, sect", page.KindSection, nil, []string{"/sect3"}, "section 3"},
